const items = $input.all();
const now = new Date();

// Calculate next week's date range (Mon-Sun)
const dayOfWeek = now.getDay();
const daysUntilMonday = dayOfWeek === 0 ? 1 : 8 - dayOfWeek;
const nextMonday = new Date(now.getTime() + daysUntilMonday * 86400000);

const weekDates = [];
for (let i = 0; i < 7; i++) {
  const d = new Date(nextMonday.getTime() + i * 86400000);
  weekDates.push(d.toISOString().split('T')[0]);
}

// Find which days already have posts
const existingDates = new Set();
for (const item of items) {
  const date = item.json['Scheduled Date'];
  const status = item.json['Status'];
  if (date && (status === 'approved' || status === 'draft')) {
    existingDates.add(date);
  }
}

const missingDays = weekDates.filter(d => !existingDates.has(d));

// Get recent posts to avoid repetition
const recentCaptions = items
  .filter(i => i.json['Status'] === 'posted')
  .slice(-5)
  .map(i => i.json['Content Pillar'])
  .join(', ');

return [{
  json: {
    weekStart: weekDates[0],
    weekEnd: weekDates[6],
    missingDays: missingDays,
    missingCount: missingDays.length,
    existingCount: 7 - missingDays.length,
    recentPillars: recentCaptions,
    weekDates: weekDates
  }
}];

