const items = $input.all();
const results = [];

for (const item of items) {
  let posts;
  try {
    const content = item.json.choices[0].message.content;
    // Handle markdown code blocks
    const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    posts = JSON.parse(cleaned);
  } catch (e) {
    // If parsing fails, create a single placeholder
    posts = [{ date: new Date().toISOString().split('T')[0], pillar: 'Menu Spotlight', caption: 'Content generation failed — please write manually', scheduledTime: '10:00', platform: 'both' }];
  }

  for (const post of posts) {
    const postId = 'POST-' + Date.now().toString(36).toUpperCase() + Math.random().toString(36).substring(2, 5).toUpperCase();
    results.push({
      json: {
        'Post ID': postId,
        'Status': 'draft',
        'Scheduled Date': post.date,
        'Scheduled Time': post.scheduledTime || '10:00',
        'Platform': post.platform || 'both',
        'Content Pillar': post.pillar,
        'Caption': post.caption,
        'Image URL': '',
        'Venue': '',
        'Event Date': '',
        'Created At': new Date().toISOString(),
        'Posted At': '',
        'Notes': 'Auto-generated by Weekly Planner. ' + (post.needsFreshPhoto ? 'NEEDS FRESH PHOTO: ' + (post.suggestedImage || '') : 'Can use library photo')
      }
    });
  }
}

return results;

